class Solution {
    public int minAddToMakeValid(String s) {
        int open = 0, close = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') open++;
            else if (close < open) close++;
            else open--;
        }
        return open + close;
    }
}
```

